using System.Text.Json;
using System.Text.Json.Serialization;
using System.Text.Json.Serialization.Metadata;

// Options with the default reflection-based resolver
var options = new JsonSerializerOptions(JsonSerializerDefaults.Web);

// 1) GetTypeInfo<T>() — strongly-typed metadata access
JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();
Console.WriteLine($"GetTypeInfo<Person> returned type: {personInfo.Type.Name}");

string json = JsonSerializer.Serialize(new Person("Alice", 42), personInfo);
Console.WriteLine($"Serialized: {json}");

// 2) TryGetTypeInfo<T>() — safe probe without exceptions
if (options.TryGetTypeInfo<Person>(out JsonTypeInfo<Person>? info))
{
    Console.WriteLine($"TryGetTypeInfo<Person> succeeded: {info!.Type.Name}");
}

// Now demonstrate the "not available" branch using a custom resolver
// that only knows about Person (not about int[]).
var limited = new JsonSerializerOptions
{
    TypeInfoResolver = new DefaultJsonTypeInfoResolver()
};
// Wrap with a resolver that filters to Person only
limited.TypeInfoResolver = limited.TypeInfoResolver.WithAddedModifier(ti =>
{
    // no-op modifier; resolver still resolves everything
});

// For a true "not available" case, use a source-gen context that only has Person
var restrictedOptions = new JsonSerializerOptions
{
    TypeInfoResolver = PersonOnlyContext.Default
};

if (restrictedOptions.TryGetTypeInfo<Person>(out var personInfo2))
{
    Console.WriteLine($"Restricted context has Person: {personInfo2!.Type.Name}");
}

if (restrictedOptions.TryGetTypeInfo<int[]>(out var arrayInfo))
{
    Console.WriteLine($"Restricted context has int[]: {arrayInfo!.Type.Name}");
}
else
{
    Console.WriteLine("TryGetTypeInfo<int[]> returned false — metadata not available");
}

// Types
public record Person(string Name, int Age);

[JsonSerializable(typeof(Person))]
public partial class PersonOnlyContext : JsonSerializerContext;
EOF
